+fn futex_rwlock_tryrdlock(word: &AtomicI32) -> c_int {
+    let state = word.load(Ordering::Acquire);
+    if state < 0 || state == i32::MAX {
+        return libc::EBUSY;
+    }
+    match word.compare_exchange(state, state + 1, Ordering::Acquire, Ordering::Relaxed) {
+        Ok(_) => 0,
+        Err(_) => libc::EBUSY,
+    }
